async function fetchUserData(userId) {
  try {
    const response = await fetch(`https://api.example.com/users/${userId}`);
    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    const data = await response.json();
    return data;
  } catch (error) {
    console.error('Failed to fetch user data:', error.message);
    // You can also rethrow or handle the error based on your application needs
  }
}

async function loadDashboard(userId) {
  try {
    const [userData, userSettings] = await Promise.all([
      fetchUserData(userId),
      fetchUserSettings(userId)
    ]);
    console.log('User Data:', userData);
    console.log('User Settings:', userSettings);
  } catch (error) {
    console.error('Error loading dashboard data:', error.message);
    alert('Sorry, something went wrong loading your data. Please try again later.');
  }
}

async function fetchUserSettings(userId) {
  try {
    const response = await fetch(`https://api.example.com/users/${userId}/settings`);
    if (!response.ok) {
      throw new Error('Settings fetch failed');
    }
    return await response.json();
  } catch (error) {
    console.warn('Failed to fetch user settings:', error.message);
    // Fall back or return default settings
    return {};
  }
}

type Readonly<T> = {
  readonly [P in keyof T]: T[P];
};

type MyPartial<T> = {
  [P in keyof T]?: T[P];
};

interface User {
  id: number;
  name: string;
  email: string;
}

const updateUser: MyPartial<User> = {
  name: "Alice"
};

type AllStrings<T> = {
  [P in keyof T]: string;
};

const user: AllStrings<User> = {
  id: "123",
  name: "Bob",
  email: "bob@example.com"
};

type OptionalStrings<T> = {
  [P in keyof T]: T[P] extends string ? T[P] | undefined : T[P];
};

const userUpdate: OptionalStrings<User> = {
  id: 1,          // number remains required
  name: undefined, // string can be undefined
  email: "alice@example.com"
};

function example(value: string | number) {
  if (typeof value === "string") {
    // TypeScript knows 'value' is string here
    console.log(value.toUpperCase());
  } else {
    // Here 'value' is number
    console.log(value.toFixed(2));
  }
}

function isString(value: any): value is string {
  return typeof value === "string";
}

class Animal {
  name: string = "";
}

class Dog extends Animal {
  bark() {
    console.log("Woof!");
  }
}

function isDog(animal: Animal): animal is Dog {
  return animal instanceof Dog;
}

interface User {
  id: number;
  name: string;
}

interface Admin {
  id: number;
  name: string;
  isAdmin: boolean;
}

function isAdmin(user: User | Admin): user is Admin {
  return (user as Admin).isAdmin !== undefined;
}

type User = {
  id: number;
  name: string;
};

type Admin = User & {
  isAdmin: boolean;
};

function isAdmin(user: User | Admin): user is Admin {
  return "isAdmin" in user;
}

function handleUser(user: User | Admin) {
  if (isAdmin(user)) {
    console.log(`${user.name} is an admin.`);
  } else {
    console.log(`${user.name} is a regular user.`);
  }
}

